#include <vector>
#include <string>
#include <algorithm>
#include <regex>

using namespace std;

bool isValidCode(const string& code) {
    if (code.empty()) return false;
    regex pattern("^[a-zA-Z0-9_]+$");
    return regex_match(code, pattern);
}

bool isValidBusinessLine(const string& business) {
    return business == "electronics" || business == "grocery" || business == "pharmacy" || business == "restaurant";
}

int getBusinessLineOrder(const string& business) {
    if (business == "electronics") return 0;
    if (business == "grocery") return 1;
    if (business == "pharmacy") return 2;
    if (business == "restaurant") return 3;
    return -1;
}

vector<string> solve(vector<string> code, vector<string> businessLine, vector<bool> isActive) {
    vector<pair<string, string>> validCoupons;
    for (size_t i = 0; i < code.size(); ++i) {
        if (isActive[i] && isValidCode(code[i]) && isValidBusinessLine(businessLine[i])) {
            validCoupons.emplace_back(businessLine[i], code[i]);
        }
    }

    sort(validCoupons.begin(), validCoupons.end(), [](const pair<string, string>& a, const pair<string, string>& b) {
        int orderA = getBusinessLineOrder(a.first);
        int orderB = getBusinessLineOrder(b.first);
        if (orderA != orderB) {
            return orderA < orderB;
        } else {
            return a.second < b.second;
        }
    });

    vector<string> result;
    for (const auto& coupon : validCoupons) {
        result.push_back(coupon.second);
    }

    return result;
}

